// TRF_FormatResponse - Format response from Agent_Conversational
const envelope = $('TRF_PrepareContext').item.json.envelope;
const agentOutput = $('Agent_Conversational').item.json;

// Extract text from agent output
let responseText = '';
let tone = 'friendly';

// Priority 1: output is a plain string (most common case)
if (typeof agentOutput.output === 'string' && agentOutput.output.trim().length > 0) {
  responseText = agentOutput.output.trim();
}
// Priority 2: output is an object with response_text
else if (agentOutput.output && typeof agentOutput.output === 'object' && agentOutput.output.response_text) {
  responseText = agentOutput.output.response_text;
  tone = agentOutput.output.tone || 'friendly';
}
// Priority 3: text at root level
else if (agentOutput.text && typeof agentOutput.text === 'string') {
  responseText = agentOutput.text.trim();
}
// Priority 4: response_text at root level
else if (agentOutput.response_text) {
  responseText = agentOutput.response_text;
}
// Fallback - ONLY if nothing else works
else {
  responseText = 'Oi! Como posso ajudar?';
}

return [{
  json: {
    envelope: envelope,
    agent_response: {
      text: responseText,
      tone: tone,
      agent: 'CONVERSATIONAL'
    }
  }
}];

// Prepare chatInput for Agent_Conversational
let envelope = $('TRG_FromOrchestrator').item.json.envelope;
if (typeof envelope === 'string') {
  try { envelope = JSON.parse(envelope); } catch(e) { envelope = { user_message: envelope, text_raw: envelope }; }
}
const userMessage = envelope.user_message || envelope.text_raw || 'Oi';
return [{ json: { chatInput: userMessage, envelope: envelope } }];
